import{_ as e,o as a,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"モダンツールエイリアス | Dotfiles (JA)","titleTemplate":":title","description":"eza、bat、ripgrep用モダンシェルエイリアス。レガシーUnixツールをより高速なRustベースの代替ツールに置き換え。","frontmatter":{"title":"モダンツールエイリアス | Dotfiles","description":"eza、bat、ripgrep用モダンシェルエイリアス。レガシーUnixツールをより高速なRustベースの代替ツールに置き換え。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"モダンツールエイリアス preview","canonical":"/ja/aliases/modern/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"モダンツールエイリアス","pageType":"docs","schemaType":"WebPage","metaTitle":"モダンツールエイリアス - Dotfiles (JP)","permalink":"/ja/aliases/modern/","sidebar":true,"meta":[{"name":"keywords","content":"modern aliases, eza, bat, ripgrep, rust cli tools, dotfiles, shell"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"eza、bat、ripgrep用モダンシェルエイリアス。レガシーUnixツールをより高速なRustベースの代替ツールに置き換え。"},{"name":"twitter:title","content":"モダンツールエイリアス - Dotfiles"},{"name":"og:title","content":"モダンツールエイリアス - Dotfiles"},{"name":"og:description","content":"eza、bat、ripgrep用モダンシェルエイリアス。レガシーUnixツールをより高速なRustベースの代替ツールに置き換え。"},{"name":"og:image:alt","content":"Dotfiles - シェルライフにフィットするシンプルな設計"},{"name":"og:locale","content":"ja_JP"}]},"headers":[],"relativePath":"ja/aliases/modern/index.md","filePath":"ja/aliases/modern/index.md","lastUpdated":1773010926000}'),o={name:"ja/aliases/modern/index.md"};function i(r,t,n,s,c,h){return a(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="モダンツールエイリアス" tabindex="-1">モダンツールエイリアス <a class="header-anchor" href="#モダンツールエイリアス" aria-label="Permalink to &quot;モダンツールエイリアス&quot;">​</a></h1><p>レガシーUnixコマンドのより高速でスマートな代替ツール。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p><code>modern.aliases.sh</code>で定義されたモダンエイリアスは、従来のUnixツールに対するRustベースの代替を提供します。これらのエイリアスは<code>chezmoi</code>によって自動的にロードされ、モダンツールが利用できない場合は標準コマンドに優雅にフォールバックします。</p><h2 id="リファレンス" tabindex="-1">リファレンス <a class="header-anchor" href="#リファレンス" aria-label="Permalink to &quot;リファレンス&quot;">​</a></h2><h3 id="ezaによるファイルリスト表示" tabindex="-1">ezaによるファイルリスト表示 <a class="header-anchor" href="#ezaによるファイルリスト表示" aria-label="Permalink to &quot;ezaによるファイルリスト表示&quot;">​</a></h3><p><code>eza</code>がインストールされている場合、<code>ls</code>を置き換えます。</p><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ls</code></td><td style="text-align:left;"><code>eza --icons</code></td><td style="text-align:left;">アイコン付きでファイルを一覧表示</td></tr><tr><td style="text-align:left;"><code>ll</code></td><td style="text-align:left;"><code>eza -alF</code></td><td style="text-align:left;">長いリスト形式</td></tr><tr><td style="text-align:left;"><code>la</code></td><td style="text-align:left;"><code>eza -a</code></td><td style="text-align:left;">隠しファイルを含むすべてのファイルを一覧表示</td></tr><tr><td style="text-align:left;"><code>lt</code></td><td style="text-align:left;"><code>eza --tree</code></td><td style="text-align:left;">ディレクトリツリーを表示</td></tr></tbody></table><p><code>eza</code>がインストールされていない場合は標準の<code>ls</code>にフォールバックします。</p><h3 id="batによるファイル内容表示" tabindex="-1">batによるファイル内容表示 <a class="header-anchor" href="#batによるファイル内容表示" aria-label="Permalink to &quot;batによるファイル内容表示&quot;">​</a></h3><p><code>bat</code>がインストールされている場合、<code>cat</code>を置き換えます。</p><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cat</code></td><td style="text-align:left;"><code>bat</code></td><td style="text-align:left;">シンタックスハイライト付きでファイル内容を表示</td></tr></tbody></table><h3 id="ripgrepによる検索" tabindex="-1">ripgrepによる検索 <a class="header-anchor" href="#ripgrepによる検索" aria-label="Permalink to &quot;ripgrepによる検索&quot;">​</a></h3><p><code>rg</code>がインストールされている場合、<code>grep</code>を置き換えます。</p><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>grep</code></td><td style="text-align:left;"><code>rg</code></td><td style="text-align:left;">Ripgrepでファイル内容を検索</td></tr></tbody></table>',15)])])}const f=e(o,[["render",i]]);export{g as __pageData,f as default};
